from pyspider.libs.base_handler import *
 import re
 class Handler(BaseHandler):
    crawl_config = {
    }
    @every(minutes=24 * 60)
    def on_start(self):
        self.crawl('http://tu.duowan.com/m/bxgif', callback=self.index_page)

    @config(age=10 * 24 * 60 * 60)
    def index_page(self, response):
        for each in response.doc('a[href^="http"]').items():
            if re.match("http://tu.duowan.com/gallery/\w+", each.attr.href, re.U):
                self.crawl(each.attr.href, callback=self.detail_page)
                
                
    @config(priority=2)
    def detail_page(self, response):
        return {
            "url": response.url,
            "title": response.doc('head > title').text(),
        }


